import { useState, useEffect } from "react";
import axios from "axios";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function AttendanceManagement() {

  const [workers, setWorkers] = useState([]);
  const [attendance, setAttendance] = useState({});
  const [date, setDate] = useState("");

  const today = new Date().toISOString().split("T")[0];

  useEffect(() => {
    fetchWorkers();
  }, []);

  // FETCH WORKERS
  const fetchWorkers = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/workers");
      setWorkers(res.data);
    } catch (err) {
      console.log("Error fetching workers:", err);
    }
  };

  // CHANGE STATUS
  const handleStatusChange = (workerId, status) => {
    setAttendance({
      ...attendance,
      [workerId]: status
    });
  };

  // SAVE ATTENDANCE
  const handleSave = async () => {

    if (!date) {
      alert("Please select date");
      return;
    }

    if (date > today) {
      alert("Future date not allowed");
      return;
    }

    const data = workers.map(worker => ({
      worker_id: worker.id,
      status: attendance[worker.id] || "Absent",
      date: date
    }));

    try {

      await axios.post("http://localhost:5000/api/attendance", data);

      alert("Attendance Saved Successfully");

    } catch (err) {

      console.log(err);
      alert("Error saving attendance");

    }

  };

  return (
    <div className="flex bg-gray-100 min-h-screen">

      <Sidebar />

      <div className="flex-1 flex flex-col">

        <Topbar />

        <div className="p-8">

          <h1 className="text-3xl font-bold mb-6">
            Attendance Management
          </h1>

          {/* DATE SELECT */}
          <div className="mb-6">

            <label className="font-semibold">
              Date
            </label>

            <input
              type="date"
              max={today}
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="border px-4 py-2 rounded ml-4"
            />

          </div>

          {/* TABLE */}
          <div className="bg-white rounded-xl shadow p-6">

            <table className="w-full">

              <thead>

                <tr className="border-b">

                  <th className="text-left py-3">
                    Worker Name
                  </th>

                  <th className="text-center">
                    Present
                  </th>

                  <th className="text-center">
                    Absent
                  </th>

                </tr>

              </thead>

              <tbody>

                {workers.map(worker => (

                  <tr key={worker.id} className="border-b">

                    <td className="py-3">
                      {worker.name}
                    </td>

                    <td className="text-center">

                      <input
                        type="radio"
                        name={`worker-${worker.id}`}
                        value="Present"
                        onChange={() =>
                          handleStatusChange(worker.id, "Present")
                        }
                      />

                    </td>

                    <td className="text-center">

                      <input
                        type="radio"
                        name={`worker-${worker.id}`}
                        value="Absent"
                        onChange={() =>
                          handleStatusChange(worker.id, "Absent")
                        }
                      />

                    </td>

                  </tr>

                ))}

              </tbody>

            </table>

            {/* SAVE BUTTON */}
            <button
              type="button"
              onClick={handleSave}
              className="mt-6 bg-orange-500 text-white px-6 py-3 rounded-xl"
            >
              Save Attendance
            </button>

          </div>

        </div>

      </div>

    </div>
  );

}
